<?php
declare(strict_types=1);require_once dirname(__DIR__,2).'/includes/auth.php';exigirRol(['usuario','admin']);$codigo=(string)($_GET['codigo']??'');$pdo=obtenerConexion();$sql='SELECT d.pedido_id FROM dte_documentos d JOIN pedidos p ON p.id=d.pedido_id WHERE d.codigo_generacion=:c';$a=['c'=>$codigo];if(($_SESSION['usuario_rol']??'')!=='admin'){$sql.=' AND p.usuario_id=:u';$a['u']=$_SESSION['usuario_id'];}$q=$pdo->prepare($sql);$q->execute($a);$id=(int)$q->fetchColumn();if(!$id){http_response_code(404);exit('Documento no disponible.');}header('Location:'.atenea_url('src/dte/documento.php?pedido='.$id));
